assignments.value:
={{ (() => {
  const output = typeof $json.output === 'string' ? $json.output.trim() : '';
  const steps = Array.isArray($json.intermediateSteps) ? $json.intermediateSteps : [];

  let latestToolResult = null;

  for (let i = steps.length - 1; i >= 0; i -= 1) {
    const observation = steps[i]?.observation;
    if (!observation) continue;

    if (typeof observation === 'object' && observation.summaryUrl) {
      latestToolResult = {
        summaryUrl: observation.summaryUrl,
        valid: observation.valid,
      };
      break;
    }

    if (typeof observation !== 'string') continue;

    try {
      const parsed = JSON.parse(observation);
      if (parsed?.summaryUrl) {
        latestToolResult = {
          summaryUrl: parsed.summaryUrl,
          valid: parsed.valid,
        };
        break;
      }
    } catch {
      // Ignora observações não-JSON e segue buscando.
    }
  }

  if (latestToolResult?.valid === false) {
    return output && !/https?:\/\/\S+/i.test(output)
      ? output
      : 'Não consegui validar esse horário para agendamento. Você pode escolher outro horário disponível?';
  }

  if (latestToolResult?.summaryUrl && latestToolResult.valid === true) {
    const outputHasUrl = /https?:\/\/\S+/i.test(output);
    if (outputHasUrl) return output;
    return (output ? output + '\n\n' : '') + 'Link de agendamento: ' + latestToolResult.summaryUrl;
  }

  return output || 'Houve um problema ao gerar o link de agendamento. Você pode tentar outro horário?';
})() }}

