const now = new Date();
const fortalezaTime = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Fortaleza',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false,
}).format(now);

const isoFormatted = now.toISOString();
const items = $input.all();

return items.map((item) => ({
  json: {
    ...item.json,
    currentDateTime: fortalezaTime,
    currentDateTimeISO: isoFormatted,
    timezone: 'America/Fortaleza',
  },
}));
